package com.antlers.support.statamic

// Generated from https://statamic.dev/tags/all-tags and https://statamic.dev/modifiers/all-modifiers.
// Refresh with scripts/generate_statamic_catalog.py.

internal val GENERATED_TAGS: List<StatamicDocItem> = listOf(
    StatamicDocItem(name = "404", displayName = "404 (Not Found)", description = "Anytime this tag is rendered — whether in a template, partial, or content, Statamic will trigger a 404 status code and render your 404 template.", example = "{{ if ! logged_in }}\n\n{{ 404 }}\n\n{{ /if }}\n\n{{ if ! success }}\n\n{{ 404 }}\n\n{{ /if }}", url = "https://statamic.dev/tags/404"),
    StatamicDocItem(name = "asset", displayName = "Asset", description = "The Asset (singular tense) tag retrieves single assets by their URL.", example = "{{ asset url=\"/img/brand/logo.png\" }}\n\n<img src=\"{{ url }}\" alt=\"{{ alt }}\" />\n\n{{ /asset }}", url = "https://statamic.dev/tags/asset"),
    StatamicDocItem(name = "assets", displayName = "Assets", description = "Used to retrieve Assets directly from a container where you can then loop, filter, and sort them in expected but exciting ways.", example = "{{ assets container=\"photoshoots\" }}\n\n<img src=\"{{ url }}\" alt=\"{{ alt }}\" />\n\n{{ /assets }}", url = "https://statamic.dev/tags/assets"),
    StatamicDocItem(name = "cache", displayName = "Cache", description = "If you find that a particular chunk of your view logic is the cause of a performance hit — perhaps you're fetching and filtering huge amount of content, or pulling data from an API, caching that portion of your template can remove alleviate any slowdown.", example = "{{ cache for=\"5 minutes\" }}\n\n{{ collection:stocks limit=\"5000\" }}\n\n<!-- probably lots of stuff happening -->\n\n{{ /collection:stocks }}\n\n{{ /cache }}", url = "https://statamic.dev/tags/cache"),
    StatamicDocItem(name = "children", displayName = "Children", description = "The Children tag allows you to loop over and fetch data from the current URL.", example = "{{ children }}\n\n{{ title }}\n\n{{ /children }}", url = "https://statamic.dev/tags/children"),
    StatamicDocItem(name = "collection", displayName = "Collection", description = "Entries are grouped into Collections and are fetched and filtered by this tag. A Collection could contain blog posts, products, or even a bag full of dad jokes. We don't judge, and neither does the Collection Tag.", example = "<ul>\n\n{{ collection from=\"blog\" }}\n\n<li><a href=\"{{ url }}\">{{ title }}</a></li>\n\n{{ /collection }}\n\n</ul>", url = "https://statamic.dev/tags/collection"),
    StatamicDocItem(name = "collection:count", displayName = "Collection:Count", description = "This tag is a clone of the collection tag but with one big difference: it only returns the total number of entries that match your set of filters.", example = "There are {{ collection:count in=\"pogs\" }} pogs in this site.", url = "https://statamic.dev/tags/collection-count"),
    StatamicDocItem(name = "collection:next", displayName = "Collection:Next", description = "If you're on a single entry page and want to show next entries in order (publish date, alphabetical, or manual), this is the tag you're looking for.", example = "{{ collection:next in=\"blog\" as=\"posts\" limit=\"2\" sort=\"date:asc\" }}\n\n{{ if no_results }}\n\nNo more posts to read!\n\n{{ /if }}\n\n{{ posts }}\n\n<div class=\"post\">\n\n...", url = "https://statamic.dev/tags/collection-next"),
    StatamicDocItem(name = "collection:previous", displayName = "Collection:Previous", description = "If you're on a single entry page and want to show previous entries in order (publish date, alphabetical, or manual), this is the tag you're looking for.", example = "{{ collection:previous in=\"blog\" as=\"posts\" limit=\"2\" sort=\"date:asc\" }}\n\n{{ if no_results }}\n\nNo more posts to read!\n\n{{ /if }}\n\n{{ posts }}\n\n<div class=\"post\">\n\n...", url = "https://statamic.dev/tags/collection-previous"),
    StatamicDocItem(name = "cookie", displayName = "Cookie", description = "Cookies provide a client-side way to store information about the user across requests. The cookie tag will let you get, set, and forget cookie data.", example = "{{ cookie }}\n\n{{ oreo }}\n\n{{ /cookie }}", url = "https://statamic.dev/tags/cookie"),
    StatamicDocItem(name = "dictionary", displayName = "Dictionary", description = "Allows you to loop through options from a Dictionary.", example = "{{ dictionary handle=\"countries\" }}\n\n{{ label }} {{ value }}\n\n{{ /dictionary }}", url = "https://statamic.dev/tags/dictionary"),
    StatamicDocItem(name = "dump", displayName = "Dump", description = "The dump tag is used for debugging data inside your current view context.", example = "{{ dump }}", url = "https://statamic.dev/tags/dump"),
    StatamicDocItem(name = "foreach", displayName = "Foreach", description = "Loop through and render values from an array of named keys and values without needing to know the keys.", example = "{{ foreach:company_info }}\n\n{{ key }}: {{ value }}<br>\n\n{{ /foreach:company_info }}\n\n<ul>\n\n{{ foreach:song_reviews as=\"song|rating\" }}\n\n<li>{{ song }}: {{ rating }}</li>\n\n...", url = "https://statamic.dev/tags/foreach"),
    StatamicDocItem(name = "form", displayName = "Form", description = "Statamic forms serve to collect, report, and reuse user submitted data. There are a number of different tags available, depending what you need to do.", example = null, url = "https://statamic.dev/tags/form"),
    StatamicDocItem(name = "form:create", displayName = "Form:Create", description = "Statamic forms serve to collect, report, and reuse user submitted data. This tag handles the HTML markup, redirect behavior, and success/error states and messages for these forms.", example = "{{ form:create in=\"contact\" }}\n\n{{ if errors }}\n\n<div class=\"bg-red-300 text-white p-2\">\n\n{{ errors }}\n\n{{ value }}<br>\n\n{{ /errors }}\n\n...", url = "https://statamic.dev/tags/form-create"),
    StatamicDocItem(name = "form:errors", displayName = "Form:Errors", description = "If a form submission encounters a validation error, you can use this tag to loop through the error messages and show your user where everything went south.", example = "{{ form:set is=\"contact\" }}\n\n{{ if {form:errors} }}\n\n<p>Oops, here's what went wrong:</p>\n\n<ul>\n\n{{ form:errors }}\n\n<li>{{ value }}</li>\n\n...", url = "https://statamic.dev/tags/form-errors"),
    StatamicDocItem(name = "form:fields", displayName = "Form:Fields", description = "To be used within the form:create tag when dynamically rendering fields.", example = "{{ form:fields }}\n\n<div class=\"p-2\">\n\n<label>{{ display }}</label>\n\n<div class=\"p-1\">{{ field }}</div>\n\n{{ if error }}\n\n<p class=\"text-gray-500\">{{ error }}</p>\n\n...", url = "https://statamic.dev/tags/form-fields"),
    StatamicDocItem(name = "form:set", displayName = "Form:Set", description = "This is a \"convenience\" wrapper tag that will set all other form tags to use the same formset.", example = "{{ form:set is=\"contact\" }}\n\n{{ if {form:errors} }}\n\n{{ form:errors }}...{{ /form:errors }}\n\n{{ /if }}\n\n{{ if {form:success} }}...{{ /if }}\n\n{{ form:create }}...{{ /form:create }}\n\n...", url = "https://statamic.dev/tags/form-set"),
    StatamicDocItem(name = "form:submission", displayName = "Form:Submission", description = "If you want to show the user the data they submitted — whether as a confirmation or to pre-populate or personalize some content — this is the easiest way to do it.", example = "{{ form:set is=\"feedback\" }}\n\n{{ if {form:success} }}\n\n{{ form:submission }}\n\nThanks for your feedback, {{ name }}.\n\nWe appreciate the {{ rating }} star rating you gave us.\n\n{{ /form:submission }}\n\n...", url = "https://statamic.dev/tags/form-submission"),
    StatamicDocItem(name = "form:submissions", displayName = "Form:Submissions", description = "This is how you fetch data and display data from form submissions. It works very much like the collection tag.", example = "{{ form:submissions in=\"feedback\" }}\n\n<div>\n\nSubmitted on {{ date }}<br>\n\nName: {{ name }}<br>\n\nRating: {{ rating }}<br>\n\nComment: {{ comment }}\n\n...", url = "https://statamic.dev/tags/form-submissions"),
    StatamicDocItem(name = "form:success", displayName = "Form:Success", description = "This is how you check if a form was successful outside of a form:create tag.", example = "{{ if {form:success in=\"contact\"} }}\n\n<p>Thanks for filling out the survey! Sorry it was so long.</p>\n\n{{ /if }}", url = "https://statamic.dev/tags/form-success"),
    StatamicDocItem(name = "get_content", displayName = "Get Content", description = "It gets content from other entries! Specify a URI or ID and fetch all the data attached to it.", example = "{{ your_entries_field }}\n\n{{ title }}, {{ url }}, {{ whatever }}\n\n{{ /your_entries_field }}", url = "https://statamic.dev/tags/get_content"),
    StatamicDocItem(name = "get_error", displayName = "Get Error", description = "The singular version of the \"Get Errors\" tag", example = null, url = "https://statamic.dev/tags/get_error"),
    StatamicDocItem(name = "get_errors", displayName = "Get Errors", description = "This tag allows you to interact with a Laravel ViewErrorBag object to output validation errors.", example = "{{ get_errors:all }}\n\n<div class=\"errors\">\n\n<p>Oops, something went wrong!</p>\n\n<ul>\n\n{{ messages }}\n\n<li>{{ message }}</li>\n\n...", url = "https://statamic.dev/tags/get_errors"),
    StatamicDocItem(name = "get_files", displayName = "Get Files", description = "The ultimate 🇨🇭Swiss Army Knife doing-stuff-with-files feature. With the get_files tag you can scan and display data on files in any directories inside your local filesystem.", example = "{{ get_files in=\"public/img/brand\" }}\n\n<img src=\"{{ file }}\" class=\"w-1/3\">\n\n{{ /get_files }}", url = "https://statamic.dev/tags/get_files"),
    StatamicDocItem(name = "get_site", displayName = "Get Site", description = "It gets a site's config, given it's handle.", example = "{{ get_site:english }}\n\n<a href=\"{{ permalink }}\">\n\nGo to {{ name }}\n\n</a>\n\n{{ /get_site:english }}", url = "https://statamic.dev/tags/get_site"),
    StatamicDocItem(name = "glide", displayName = "Glide", description = "The Glide tag makes it easy to manipulate images on the fly – from resizing and cropping to adjustments (like sharpness and contrast) and image effects (like pixelate and sepia).", example = "{{ glide src=\"image.jpg\" width=\"1280\" height=\"800\" }}", url = "https://statamic.dev/tags/glide"),
    StatamicDocItem(name = "glide:batch", displayName = "Glide:Batch", description = "Use glide:batch to manipulate a whole batch of <img> tags with Glide.", example = "{{ glide:batch width=\"600\" height=\"400\" fit=\"crop\" }}\n\n{{ page:content }}\n\n{{ /glide:batch }}", url = "https://statamic.dev/tags/glide-batch"),
    StatamicDocItem(name = "glide:data_url", displayName = "Glide:Data_URL", description = "Use glide:data_url to output a manipulated image as a Data URL.", example = "{{ glide:data_url src=\"image.jpg\" width=\"1280\" height=\"800\" format=\"webp\" }}", url = "https://statamic.dev/tags/glide-data-url"),
    StatamicDocItem(name = "increment", displayName = "Increment", description = "Each time an increment tag is parsed, an index is incremented by one and displayed.", example = "{{ items }}\n\n{{ increment }}\n\n{{ /items }}", url = "https://statamic.dev/tags/increment"),
    StatamicDocItem(name = "installed", displayName = "Installed", description = "Determine whether or not a Composer package is installed.", example = "{{ if {installed:statamic/seo-pro} }}\n\n{{ seo_pro:meta }}\n\n{{ else }}\n\n{{ partial:seo }}\n\n{{ /if }}", url = "https://statamic.dev/tags/installed"),
    StatamicDocItem(name = "link", displayName = "Link", description = "Generate fully qualified URLs with the option to include your domain.", example = "{{ link to=\"fanny-packs\" }}\n\n{{ link to=\"fanny-packs\" absolute=\"true\" }}", url = "https://statamic.dev/tags/link"),
    StatamicDocItem(name = "locales", displayName = "Locales", description = "Create links to localized content.", example = "<ul>\n\n{{ locales }}\n\n<li><a href=\"{{ permalink }}\">View in {{ locale:name }}</a></li>\n\n{{ /locales }}\n\n</ul>", url = "https://statamic.dev/tags/locales"),
    StatamicDocItem(name = "locales:count", displayName = "Locales:Count", description = "Get the number of localizations.", example = "{{ locales:count }}\n\n{{ locales:count self=\"false\" }}", url = "https://statamic.dev/tags/locales-count"),
    StatamicDocItem(name = "loop", displayName = "Loop", description = "Create and iterate through a loop a specific number of times or between a range.", example = "{{ loop times=\"10\" }}\n\n{{ value }}\n\n{{ /loop }}", url = "https://statamic.dev/tags/loop"),
    StatamicDocItem(name = "markdown", displayName = "Markdown", description = "Transform Markdown content written inline in your template. For when you just can't be bothered to write HTML or make another variable.", example = "<article class=\"mx-auto max-w-lg\">\n\n{{ markdown }}\n\n# My Favorite Nickelodeon Shows\n\n- Kenan & Kel\n\n- All That\n\n- Double Dare\n\n...", url = "https://statamic.dev/tags/markdown"),
    StatamicDocItem(name = "markdown:indent", displayName = "Markdown:Indent", description = "This tag is used for transforming Markdown while ignoring whitespace in your view files.", example = "<article class=\"mx-auto max-w-lg\">\n\n{{ markdown:indent }}\n\n# My Favorite Nickelodeon Shows\n\n- Kenan & Kel\n\n- All That\n\n- Double Dare\n\n...", url = "https://statamic.dev/tags/markdown-indent"),
    StatamicDocItem(name = "mix", displayName = "Mix", description = "The Mix tag is used in tandem with Laravel Mix to return the path to versioned CSS and JavaScript files.", example = "// CSS\n\n<link href=\"{{ mix src='/css/tailwind.css' }}\" rel=\"stylesheet\">\n\n// JavaScript\n\n<script src=\"{{ mix src='/js/app.js' }}\"></script>", url = "https://statamic.dev/tags/mix"),
    StatamicDocItem(name = "mount_url", displayName = "Mount URL", description = "The Mount URL tag is used to return the URL to a collection's mount entry.", example = "<a href=\"{{ mount_url handle=\"blog\" }}\">Read Our Blog</a>", url = "https://statamic.dev/tags/mount_url"),
    StatamicDocItem(name = "nav", displayName = "Nav", description = "The nav tags are designed to help your users navigate through your hierarchy of navigations and collections.", example = "// The \"links\" nav\n\n{{ nav:links }} ... {{ /nav:links }}", url = "https://statamic.dev/tags/nav"),
    StatamicDocItem(name = "nav:breadcrumbs", displayName = "Nav:Breadcrumbs", description = "Breadcrumbs are a common form of site navigation designed to give the user a view of where the current page is in the parent/child hierarchy. Much like the crumbs left by a certain little German boy — they lead from wherever you are, all the way back home.", example = "<ul class=\"breadcrumbs\">\n\n{{ nav:breadcrumbs }}\n\n<li{{ if is_current }} class=\"current\"{{ /if }}>\n\n<a href=\"{{ url }}\">{{ title }}</a>\n\n</li>\n\n{{ /nav:breadcrumbs }}\n\n...", url = "https://statamic.dev/tags/nav-breadcrumbs"),
    StatamicDocItem(name = "nocache", displayName = "No Cache", description = "When using a broader caching solution (like static caching or the cache tag) you may want to keep a chunk of your template dynamic.", example = "{{ nav }} ... {{ /nav }}\n\n{{ nocache }}\n{{ if logged_in }}\n\nWelcome back, {{ current_user:name }}\n\n{{ else }}\n\nHello, Guest!\n\n{{ /if }}\n...", url = "https://statamic.dev/tags/nocache"),
    StatamicDocItem(name = "oauth", displayName = "OAuth", description = "If you're using OAuth to manage user authentication, you may find you need to generate login URLs at some point. Here's how you do it.", example = "<a href=\"{{ oauth provider=\"github\" }}\">Sign In with Github</a>", url = "https://statamic.dev/tags/oauth"),
    StatamicDocItem(name = "obfuscate", displayName = "Obfuscate", description = "Whenever you need to obfuscate something, reach for the obfuscate tag. It's an obfuscating good time.", example = "{{ obfuscate }}\n\n[email protected]\n\n{{ /obfuscate }}", url = "https://statamic.dev/tags/obfuscate"),
    StatamicDocItem(name = "parent", displayName = "Parent", description = "The Parent tag fetches data from the \"parent\" page — the URL one level above the current one. For example, the parent of this very URL (/tags/parent) is /tags, and the parent title is \"Tags\".", example = "{{ parent }}\n\n// Would return \"/tags\"", url = "https://statamic.dev/tags/parent"),
    StatamicDocItem(name = "partial", displayName = "Partial", description = "Partials are reusable views that may find themselves in any number of other layouts, templates, and other partials.", example = "// This will import /resources/views/blog/_card.antlers.html\n\n{{ partial:blog/card }}", url = "https://statamic.dev/tags/partial"),
    StatamicDocItem(name = "partial:exists", displayName = "Partial:Exists", description = "Checks if a partial exists.", example = "{{ if {partial:exists src=\"mypartial\" } }}\n\nIt exists\n\n{{ else }}\n\nIt doesn't.\n\n{{ /if }}", url = "https://statamic.dev/tags/partial-exists"),
    StatamicDocItem(name = "partial:if_exists", displayName = "Partial:If_Exists", description = "Renders a partial if it exists.", example = "{{ partial:if_exists src=\"mypartial\" }}", url = "https://statamic.dev/tags/partial-if-exists"),
    StatamicDocItem(name = "protect:password_form", displayName = "Protect:Password_Form", description = "This tag is used to create a custom content password protection form.", example = "{{ protect:password_form }}\n\n{{ if invalid_token }}\n\nNo token has been provided.\n\n{{ else }}\n\n{{ if error }}\n\n<div class=\"error\">{{ error }}</div>\n\n...", url = "https://statamic.dev/tags/protect-password_form"),
    StatamicDocItem(name = "redirect", displayName = "Redirect", description = "Anytime this tag is rendered — whether in a template, partial, or content, Statamic will redirect the visitor to the specified URL.", example = "{{ if ! logged_in }}\n\n{{ redirect to=\"/\" }}\n\n{{ /if }}", url = "https://statamic.dev/tags/redirect"),
    StatamicDocItem(name = "route", displayName = "Route", description = "The route tag allows you to generate the full URL for a given named route, including any parameters.", example = "<form action=\"{{ route:bacon.update :bacon=\"id\" }}\">\n\n... yummy bacon goodness\n\n</form>", url = "https://statamic.dev/tags/route"),
    StatamicDocItem(name = "scope", displayName = "Scope", description = "Used to push all of the \"root\", or page scope data into an array to be used however you see fit.", example = "---\n\ntitle: Grimmace Shake\n\n---\n\n{{ scope:stuff }}\n\n<h1>{{ stuff:title }}</h1>\n\n{{ /scope:stuff }}", url = "https://statamic.dev/tags/scope"),
    StatamicDocItem(name = "search", displayName = "Search", description = "This is how you do search. This is the tag you're looking for.", example = "{{ search:results }}\n\n{{ if no_results }}\n\n<h2>No results.</h2>\n\n{{ else }}\n\n<a href=\"{{ url }}\" class=\"result\">\n\n<h2>{{ title }}</h2>\n\n...", url = "https://statamic.dev/tags/search"),
    StatamicDocItem(name = "section", displayName = "Section", description = "The section tag is a useful way to abstract and reuse your views by extracting a section of markup that can then be rendered elsewhere with a yield tag.", example = "// The Template\n\n<h1>{{ title }}</h1>\n\n{{ content }}\n\n{{ section:sidebar }}\n\n<h2>About the Author</h2>\n\n<div>\n\n...", url = "https://statamic.dev/tags/section"),
    StatamicDocItem(name = "session", displayName = "Session", description = "Sessions provide a stateless way to store information about the user across requests. The session tag will let you get, set, and forget session data.", example = "{{ session }}\n\n{{ message }}\n\n{{ /session }}", url = "https://statamic.dev/tags/session"),
    StatamicDocItem(name = "session:dump", displayName = "Session:Dump", description = "The contents of the user session can be dumped to the browser. You never know when you need to peek inside the black box.", example = "{{ session:dump }}", url = "https://statamic.dev/tags/session-dump"),
    StatamicDocItem(name = "session:flash", displayName = "Session:Flash", description = "Flash data is session data that is only kept for a single request. It is most often used for success/failure messages that automatically disappear after a page refresh.", example = "{{ session:flash message=\"You did it!\" }}", url = "https://statamic.dev/tags/session-flash"),
    StatamicDocItem(name = "session:flush", displayName = "Session:Flush", description = "The flush tag will wipe the entire user session. This will also sign a user out if they're signed in.", example = "{{ session:flush }}", url = "https://statamic.dev/tags/session-flush"),
    StatamicDocItem(name = "session:forget", displayName = "Session:Forget", description = "Remove variables from the user session by passing the names of the variables into the keys parameter.", example = "{{ session:forget keys=\"likes|referral\" }}", url = "https://statamic.dev/tags/session-forget"),
    StatamicDocItem(name = "session:has", displayName = "Session:Has", description = "This tag checks the session to see if any given keys exist in a user session.", example = "{{ if {session:has key=\"entered_survey\"} }}\n\n<p>You already filled out the survey. Thanks for your feedback!</p>\n\n{{ /if }}", url = "https://statamic.dev/tags/session-has"),
    StatamicDocItem(name = "session:set", displayName = "Session:Set", description = "Data set in the session will be available in all future requests until such time that the session is cleared over time (sessions eventually expire) or intentionally. Session variables can be retrieved with the main session tag.", example = "{{ session:set entered_survey=\"true\" }}", url = "https://statamic.dev/tags/session-set"),
    StatamicDocItem(name = "svg", displayName = "SVG", description = "The SVG tag renders inline SVGs and lets you easily set attributes on the <svg> element.", example = "// Using resources/svg/circle.svg\n\n{{ svg src=\"circle\" class=\"fill-current text-teal\" }}\n\n// Using public/img/icons/square\n\n{{ svg src=\"img/icons/square\" class=\"fill-current text-mint\" }}\n\n// Using a variable `promo_graphic` (defined in your blueprint)\n\n{{ svg :src=\"promo_graphic\" class=\"fill-current text-orange\" }}", url = "https://statamic.dev/tags/svg"),
    StatamicDocItem(name = "switch", displayName = "Switch", description = "Each time a switch tag is rendered it will return the next value from its between parameter until it reaches the end where it will start all over again.", example = "<table>\n\n{{ collection:shows }}\n\n<tr class=\"{{ switch between='bg-white|bg-grey-100' }}\">\n\n<th>{{ title }}</th>\n\n<td>{{ rating }}</td>\n\n<tr>\n\n...", url = "https://statamic.dev/tags/switch"),
    StatamicDocItem(name = "taxonomy", displayName = "Taxonomy", description = "Taxonomy terms are grouped into taxonomies and are fetched and filtered by this tag. A taxonomy could contain tags, categories, or sock colors.", example = "<ul>\n\n{{ taxonomy from=\"tags\" }}\n\n<li><a href=\"{{ url }}\">{{ title }}</a></li>\n\n{{ /taxonomy }}\n\n</ul>", url = "https://statamic.dev/tags/taxonomy"),
    StatamicDocItem(name = "taxonomy:count", displayName = "Taxonomy:Count", description = "This tag is a clone of the taxonomy tag but with one big difference: it only returns the total number of terms that match your set of filters.", example = "There are {{ taxonomy:count in=\"tags\" }} tags in this site.", url = "https://statamic.dev/tags/taxonomy-count"),
    StatamicDocItem(name = "trans", displayName = "Translate", description = "Retrieve a string from a language file in the current locale.", example = "{{ trans:foo.bar }} or {{ trans key=\"foo.bar\" }}", url = "https://statamic.dev/tags/trans"),
    StatamicDocItem(name = "user:can", displayName = "User:Can", description = "Anything inside the user:can tag will only be rendered if the user has the specified permission.", example = "{{ user:can do=\"edit faq entries\" }}\n\n<a href=\"{{ edit_url }}\">Edit this Page</a>\n\n{{ /user:can }}", url = "https://statamic.dev/tags/user-can"),
    StatamicDocItem(name = "user:forgot_password_form", displayName = "User:Forgot_Password_Form", description = "This tag is used to create a \"forgot my password\" form for your users.", example = "{{ user:forgot_password_form reset_url=\"/reset-password\" }}\n\n{{ if errors }}\n\n<div class=\"bg-red-300 text-white p-2\">\n\n{{ errors }}\n\n{{ value }}<br>\n\n{{ /errors }}\n\n...", url = "https://statamic.dev/tags/user-forgot_password_form"),
    StatamicDocItem(name = "user:in", displayName = "User:In", description = "Anything inside the user:in tag will only be rendered if the user is in the specified group.", example = "{{ user:in group=\"coaches\" }}\n\n<ul>\n\n{{ assets in=\"pdf\" }}\n\n<li><a href=\"{{ url }}\">{{ title }}</a></li>\n\n{{ /assets }}\n\n</ul>\n\n...", url = "https://statamic.dev/tags/user-in"),
    StatamicDocItem(name = "user:is", displayName = "User:Is", description = "Anything inside the user:is tag will only be rendered if the user has a specific role.", example = "{{ user:is role=\"author\" }}\n\n<div class=\"markdown\">\n\n{{ content }}\n\n</div>\n\n{{ /user:is }}", url = "https://statamic.dev/tags/user-is"),
    StatamicDocItem(name = "user:login_form", displayName = "User:Login_Form", description = "If you want to build a login form for your users, this is the easiest way to do it.", example = "{{ user:login_form }}\n\n{{ if errors }}\n\n<div class=\"bg-red-300 text-white p-2\">\n\n{{ errors }}\n\n{{ value }}<br>\n\n{{ /errors }}\n\n...", url = "https://statamic.dev/tags/user-login_form"),
    StatamicDocItem(name = "user:logout", displayName = "User:Logout", description = "This will immediately log a user out and redirect to /somewhere if the condition is met.", example = "{{ if should_logout_for_whatever_reason }}\n\n{{ user:logout redirect=\"/somewhere\" }}\n\n{{ /if }}", url = "https://statamic.dev/tags/user-logout"),
    StatamicDocItem(name = "user:logout_url", displayName = "User:Logout_URL", description = "Where the user should be redirected after logging out. Defaults to the home page.", example = "<a href=\"{{ user:logout_url }}\">Log out</a>", url = "https://statamic.dev/tags/user-logout_url"),
    StatamicDocItem(name = "user:password_form", displayName = "User:Password_Form", description = "User tags are designed for sites that have areas or features behind a login. The user:password_form tag allows your users to change their password.", example = "{{ user:password_form }}\n\n{{ if errors }}\n\n<div class=\"bg-red-300 text-white p-2\">\n\n{{ errors }}\n\n{{ value }}<br>\n\n{{ /errors }}\n\n...", url = "https://statamic.dev/tags/user-password_form"),
    StatamicDocItem(name = "user:profile", displayName = "User:Profile", description = "Fetching user data made easy.", example = "{{ user }}\n\nThe current user's name is {{ name }}.\n\n{{ /user }}", url = "https://statamic.dev/tags/user-profile"),
    StatamicDocItem(name = "user:profile_form", displayName = "User:Profile_Form", description = "User tags are designed for sites that have areas or features behind a login. The user:profile_form tag helps you build a user profile edit form for existing users based on your user Blueprint.", example = "{{ user:profile_form }}\n\n{{ if errors }}\n\n<div class=\"bg-red-300 text-white p-2\">\n\n{{ errors }}\n\n{{ value }}<br>\n\n{{ /errors }}\n\n...", url = "https://statamic.dev/tags/user-profile_form"),
    StatamicDocItem(name = "user:register_form", displayName = "User:Register_Form", description = "User tags are designed for sites that have areas or features behind a login. The user:registration_form tag helps you build a public registration form for new users.", example = "{{ user:register_form }}\n\n{{ if errors }}\n\n<div class=\"bg-red-300 text-white p-2\">\n\n{{ errors }}\n\n{{ value }}<br>\n\n{{ /errors }}\n\n...", url = "https://statamic.dev/tags/user-register_form"),
    StatamicDocItem(name = "user:reset_password_form", displayName = "User:Reset_Password_Form", description = "This tag is used to to set a new password after a user has received the reset link from the \"forgot my password\" form.", example = "{{ user:reset_password_form }}\n\n{{ if success }}\n\n<p class=\"alert alert-success\">Password has been reset.</p>\n\n{{ elseif url_invalid }}\n\n<p class=\"alert alert-danger\">This reset URL is invalid.</p>\n\n{{ else }}\n\n...", url = "https://statamic.dev/tags/user-reset_password_form"),
    StatamicDocItem(name = "user_groups", displayName = "User_Groups", description = "The user_groups tag is used to return any groups you have added to collate the users on your site.", example = "<ul>\n\n{{ user_groups }}\n\n<li>{{ handle }}</li>\n\n{{ /user_groups }}\n\n</ul>", url = "https://statamic.dev/tags/user-groups"),
    StatamicDocItem(name = "user_roles", displayName = "User_Roles", description = "The user_roles tag is used to return any roles you have added to collate the users on your site.", example = "<ul>\n\n{{ user_roles }}\n\n<li>{{ handle }}</li>\n\n{{ /user_roles }}\n\n</ul>", url = "https://statamic.dev/tags/user-roles"),
    StatamicDocItem(name = "users", displayName = "Users", description = "The users tag can be used to fetch, filter, and iterate over Users and their data.", example = "<ul>\n\n{{ users }}\n\n<li>{{ name }}</li>\n\n{{ /users }}\n\n</ul>", url = "https://statamic.dev/tags/users"),
    StatamicDocItem(name = "vite", displayName = "Vite", description = "This tag is used in tandem with the Vite build tool to return the path to CSS and JavaScript files.", example = "{{ vite src=\"resources/js/app.js|resources/css/app.css\" }}", url = "https://statamic.dev/tags/vite"),
    StatamicDocItem(name = "vite:content", displayName = "Vite:Content", description = "This tag is used in tandem with the Vite build tool to return the contents of CSS and JavaScript files.", example = "<style>\n\n{{ vite:content src=\"resources/css/app.css\" }}\n\n</style>\n\n<script>\n\n{{ vite:content src=\"resources/js/app.js\" }}\n\n</script>", url = "https://statamic.dev/tags/vite-content"),
    StatamicDocItem(name = "yield", displayName = "Yield", description = "The yield tag is a useful way to abstract and reuse your views by displaying content or markup extracted in a template by the section tag.", example = "// The Template\n\n<h1>{{ title }}</h1>\n\n{{ content }}\n\n{{ section:sidebar }}\n\n<h2>About the Author</h2>\n\n<div>\n\n...", url = "https://statamic.dev/tags/yield")
)

internal val GENERATED_MODIFIERS: List<StatamicDocItem> = listOf(
    StatamicDocItem(name = "add", displayName = "add", description = "Add a value or another variable to your variable. Pass an integer or the name of a second variable as the parameter. Also supports + as shorthand.", example = "{{ books | add:5 }}\n\n{{ books | add:magazines }}\n\n{{ books | +:magazines }}", url = "https://statamic.dev/modifiers/add"),
    StatamicDocItem(name = "add_slashes", displayName = "add_slashes", description = "Modifies a string by adding backslashes before characters that need to be escaped. These characters are:", example = "{{ summary | add_slashes }}", url = "https://statamic.dev/modifiers/add_slashes"),
    StatamicDocItem(name = "ampersand_list", displayName = "ampersand_list", description = "Turn a simple array into a comma delimited string with a friendly little ampersand between the last two items.", example = "{{ fruits | ampersand_list }}", url = "https://statamic.dev/modifiers/ampersand_list"),
    StatamicDocItem(name = "antlers", displayName = "antlers", description = "Parses the given value as an Antlers template.", example = "{{ title | antlers }}", url = "https://statamic.dev/modifiers/antlers"),
    StatamicDocItem(name = "as", displayName = "as", description = "Alias an array variable as another name, allowing you to massage your data to reused shared components and templates.", example = "{{ blocks as=\"sets\" }}\n\n{{ sets }}\n\n{{ partial:type }}\n\n{{ /sets }}\n\n{{ /blocks }}", url = "https://statamic.dev/modifiers/as"),
    StatamicDocItem(name = "ascii", displayName = "ascii", description = "Replaces all non-ASCII characters with their closest ASCII counterparts and removes any unsupported characters completely. This is very useful for converting foreign language strings into something more code-friendly.", example = "{{ title | ascii }}", url = "https://statamic.dev/modifiers/ascii"),
    StatamicDocItem(name = "at", displayName = "at", description = "Returns the single character at a given position in a string. It starts at zero with the first character.", example = "{{ title | at:21 }}", url = "https://statamic.dev/modifiers/at"),
    StatamicDocItem(name = "attribute", displayName = "attribute", description = "When you're writing partials, you might find yourself passing variables that will ultimately just be used in HTML attributes, like this:", example = "<input\n\ntype=\"text\"\n\n{{ if name }}name=\"{{ name }}\"{{ /if }}\n\n{{ if class }}class=\"{{ class }}\"{{ /if }}\n\n{{ if mandatory }}required{{ /if }}\n\n/>", url = "https://statamic.dev/modifiers/attribute"),
    StatamicDocItem(name = "background_position", displayName = "background_position", description = "Converts an asset focal point value (eg. 50-30) into a value suitable for the background-position css property.", example = "background-position: {{ focus | background_position }};", url = "https://statamic.dev/modifiers/background_position"),
    StatamicDocItem(name = "backspace", displayName = "backspace", description = "Removes a specified number of characters from the end of a string.", example = "{{ title | backspace:29 }}", url = "https://statamic.dev/modifiers/backspace"),
    StatamicDocItem(name = "bard_html", displayName = "bard_html", description = "Converts any Bard data to an HTML string (excluding sets). Bard data can be either:", example = "{{ main_content | raw | bard_html }}", url = "https://statamic.dev/modifiers/bard_html"),
    StatamicDocItem(name = "bard_items", displayName = "bard_items", description = "Converts any Bard data to a flat array of ProseMirror nodes and marks. Bard data can be either:", example = "{{ main_content | raw | bard_items }}\n\n{{ main_content | raw | bard_items | where:type:image | first | bard_html }}\n\n{{ links = main_content | raw | bard_items | where:type:link }}\n\n{{ links }}\n\n{{ node | bard_text }} - {{ attrs:href }}\n\n{{ /links }}", url = "https://statamic.dev/modifiers/bard_items"),
    StatamicDocItem(name = "bard_text", displayName = "bard_text", description = "Converts any Bard data to a plain text string (excluding sets). Bard data can be either:", example = "{{ main_content | raw | bard_text }}\n\n{{ main_content | raw | bard_text | read_time }}", url = "https://statamic.dev/modifiers/bard_text"),
    StatamicDocItem(name = "bool_string", displayName = "bool_string", description = "Converts a truthy value to the string true and a falsy to the string false. Check out https://www.php.net/manual/en/language.types.boolean.php to see what PHP considers truthy and falsy.", example = "{{ no | bool_string }}\n\n{{ yes | bool_string }}\n\n{{ sure | bool_string }}", url = "https://statamic.dev/modifiers/bool_string"),
    StatamicDocItem(name = "camelize", displayName = "camelize", description = "Returns a camelCase version of a string. Trims surrounding spaces, capitalizes letters following digits, spaces, dashes and underscores, and removes spaces, dashes and underscores. It's a programmer-type thing, great for converting between code styles.", example = "{{ method | camelize }}", url = "https://statamic.dev/modifiers/camelize"),
    StatamicDocItem(name = "cdata", displayName = "cdata", description = "Wraps a string in CDATA tags, useful for formatting characters properly in XML.", example = "{{ title | cdata }}", url = "https://statamic.dev/modifiers/cdata"),
    StatamicDocItem(name = "ceil", displayName = "ceil", description = "Rounds a number up to the next whole number.", example = "{{ number | ceil }}", url = "https://statamic.dev/modifiers/ceil"),
    StatamicDocItem(name = "chunk", displayName = "chunk", description = "Break arrays or collections into smaller (wait for it) chunks of any given size. This is useful for performing various gymnastics with your HTML markup.", example = "{{ collection:news as=\"posts\" limit=\"6\" }}\n\n{{ posts chunk=\"3\" }}\n\n<div class=\"flex space-x-4\">\n\n{{ chunk }}\n\n<a href=\"{{ url }}\" class=\"bg-purple-800 text-white p-4\">\n\n{{ title }}\n\n...", url = "https://statamic.dev/modifiers/chunk"),
    StatamicDocItem(name = "classes", displayName = "classes", description = "This conditionally compiles a CSS class string using Laravel's Arr::toCssClasses() method.", example = "<div class=\"text-sm {{ ['p-4' => true, 'font-bold' => is_active, 'bg-red' => has_error] | classes }}\">\n\n//\n\n</div>", url = "https://statamic.dev/modifiers/classes"),
    StatamicDocItem(name = "collapse", displayName = "collapse", description = "Collapses an array of arrays into a flat array. If duplicate keys exist they will get stomped over.", example = "{{ numbers | collapse }}", url = "https://statamic.dev/modifiers/collapse"),
    StatamicDocItem(name = "collapse_whitespace", displayName = "collapse_whitespace", description = "Trims a string and replaces consecutive whitespace characters with\n\na single space. This includes tabs and newline characters, as well as\n\nmultibyte whitespace such as the thin space and ideographic space.", example = "{{ title | collapse_whitespace }}", url = "https://statamic.dev/modifiers/collapse_whitespace"),
    StatamicDocItem(name = "compact", displayName = "compact", description = "Converts a comma-delimited list of variable names into an array that can be used anywhere. Arrays are accepted.", example = "{{ \"stuff:one, title, stuff:two\" | compact | ul }}", url = "https://statamic.dev/modifiers/compact"),
    StatamicDocItem(name = "console_log", displayName = "console_log", description = "Debug a variable by dumping its contents to your browser's JavaScript's console via console.log.", example = "{{ fruit | console_log }}", url = "https://statamic.dev/modifiers/console_log"),
    StatamicDocItem(name = "contains", displayName = "contains", description = "Check if a value contains another value. Supports both strings and arrays.", example = "{{ if summary | contains('BEST') }}\n\n{{ if summary | contains('BEST', true) }}\n\n{{ if summary | contains('adjective') }}\n\n{{ if summary | contains('noun') }}", url = "https://statamic.dev/modifiers/contains"),
    StatamicDocItem(name = "contains_all", displayName = "contains_all", description = "Search a string against multiple needles and return true if all are found, otherwise false. Case-insensitive.", example = "{{ if summary | contains_all('best', 'worst') }}\n\n{{ if summary | contains_all('best', 'better') }}", url = "https://statamic.dev/modifiers/contains_all"),
    StatamicDocItem(name = "contains_any", displayName = "contains_any", description = "Search a string against multiple needles and return true if any are found, otherwise false. Case-insensitive.", example = "{{ if summary | contains_any('good', 'better', 'best') }}", url = "https://statamic.dev/modifiers/contains_any"),
    StatamicDocItem(name = "count", displayName = "count", description = "Count the number of items in an array.", example = "{{ fruit | count }}", url = "https://statamic.dev/modifiers/count"),
    StatamicDocItem(name = "count_substring", displayName = "count_substring", description = "Returns the number of occurrences of search term in a given string. By default,\n\nthe comparison is case-insensitive, but can be made sensitive by setting the second parameter to true.", example = "{{ quote | count_substring('dude') }}", url = "https://statamic.dev/modifiers/count_substring"),
    StatamicDocItem(name = "dashify", displayName = "dashify", description = "Returns a lowercase and trimmed string separated by dashes. Dashes are inserted before uppercase characters (with the exception of the first character of the string), and in place of spaces as well as underscores.", example = "{{ title | dashify }}", url = "https://statamic.dev/modifiers/dashify"),
    StatamicDocItem(name = "days_ago", displayName = "days_ago", description = "Returns the number of days since a given date variable. Statamic will attempt to parse any string as a date, but try to keep it in the least ambiguous date format possible.", example = "{{ date | days_ago }}", url = "https://statamic.dev/modifiers/days_ago"),
    StatamicDocItem(name = "decode", displayName = "decode", description = "Convert all HTML entities to their applicable characters via PHP's html_entity_decode() function. Will convert both double and single quotes. This is the opposite of the entities modifier.", example = "{{ string | decode }}", url = "https://statamic.dev/modifiers/decode"),
    StatamicDocItem(name = "deslugify", displayName = "deslugify", description = "Replaces all hyphens and underscores in a string with spaces. The opposite of dashify.", example = "{{ title | deslugify }}", url = "https://statamic.dev/modifiers/deslugify"),
    StatamicDocItem(name = "divide", displayName = "divide", description = "Divide a value or another variable by your variable. Pass an integer or the name of a second variable as the parameter.", example = "{{ bacon | divide(\$skillets) }}\n\n{{ skillets | divide(3) }}", url = "https://statamic.dev/modifiers/divide"),
    StatamicDocItem(name = "dl", displayName = "dl", description = "Turn a key/value array, otherwise known as a YAML mapping, into an HTML definition list.", example = "{{ food | dl }}", url = "https://statamic.dev/modifiers/dl"),
    StatamicDocItem(name = "dump", displayName = "dump", description = "Dump a variable to the browser and see under the hood with data types and array exportation. Definitely just for debugging when in development.", example = "{{ food | dump }}", url = "https://statamic.dev/modifiers/dump"),
    StatamicDocItem(name = "embed_url", displayName = "embed_url", description = "Converts a Youtube or Vimeo link to their embed URLs.", example = "{{ youtube | embed_url }}\n\n{{ vimeo | embed_url }}\n\n{{ other | embed_url }}", url = "https://statamic.dev/modifiers/embed_url"),
    StatamicDocItem(name = "ends_with", displayName = "ends_with", description = "Returns true if the value ends with a given string. This comparison is case-insensitive.", example = "{{ if (punchline | ends_with('she said!')) }}\n\n{{ if (punchline | ends_with('your mom!')) }}", url = "https://statamic.dev/modifiers/ends_with"),
    StatamicDocItem(name = "ensure_left", displayName = "ensure_left", description = "Ensures that the string begins with a specified string. If it doesn't, it will now.", example = "{{ links }}\n\n<li>{{ value | ensure_left('http://') }}</li>\n\n{{ /links }}", url = "https://statamic.dev/modifiers/ensure_left"),
    StatamicDocItem(name = "ensure_right", displayName = "ensure_right", description = "Ensures that the string ends with a specified string. If it doesn't, it will now.", example = "{{ links }}\n\n<li>{{ value | ensure_right('.com') }}</li>\n\n{{ /links }}", url = "https://statamic.dev/modifiers/ensure_right"),
    StatamicDocItem(name = "entities", displayName = "entities", description = "Encode a string with HTML entities via PHP's htmlentities() function. This is the opposite of the decode modifier.", example = "{{ string | entities }}", url = "https://statamic.dev/modifiers/entities"),
    StatamicDocItem(name = "excerpt", displayName = "excerpt", description = "Generate an excerpt from your content.", example = "{{ books | excerpt }}", url = "https://statamic.dev/modifiers/excerpt"),
    StatamicDocItem(name = "explode", displayName = "explode", description = "Breaks a string into an array of strings split on a given delimiter.", example = "{{ places | explode(',') | ul }}", url = "https://statamic.dev/modifiers/explode"),
    StatamicDocItem(name = "favicon", displayName = "favicon", description = "Given a valid URL will generate a proper favicon meta tag.", example = "{{ icon | favicon }}", url = "https://statamic.dev/modifiers/favicon"),
    StatamicDocItem(name = "filter_empty", displayName = "filter_empty", description = "Filters out null values from an array.", example = "{{ favorite_things | filter_empty }}", url = "https://statamic.dev/modifiers/filter_empty"),
    StatamicDocItem(name = "first", displayName = "first", description = "Returns the first X characters of a string, where X is any positive integer, or the first item in an array.", example = "{{ title | first(4) }}\n\n{{ array | first }}", url = "https://statamic.dev/modifiers/first"),
    StatamicDocItem(name = "flatten", displayName = "flatten", description = "Flattens a multi-dimensional array (a Grid or Replicator field for example) into a single dimension.", example = "{{ ingredients | flatten }}", url = "https://statamic.dev/modifiers/flatten"),
    StatamicDocItem(name = "flip", displayName = "flip", description = "Swaps the keys with their corresponding values. The old switcharoo.", example = "{{ favorites | json }}\n\n{{ favorites | flip | json }}", url = "https://statamic.dev/modifiers/flip"),
    StatamicDocItem(name = "floor", displayName = "floor", description = "Rounds a number down to the next whole number.", example = "{{ number | floor }}", url = "https://statamic.dev/modifiers/floor"),
    StatamicDocItem(name = "format", displayName = "format", description = "Given a date string, or anything that sort of looks like a date string, format will convert it to a Carbon instance and allow you to format it with PHP's datetime format variables.", example = "{{ event_date | format('Y-m-d') }}", url = "https://statamic.dev/modifiers/format"),
    StatamicDocItem(name = "format_number", displayName = "format_number", description = "Format a number with grouped thousands and decimal points. In other words, make it look nice.", example = "{{ lucky_number | format_number(1, ',', ',') }}", url = "https://statamic.dev/modifiers/format_number"),
    StatamicDocItem(name = "format_translated", displayName = "format_translated", description = "Given a date string, or anything that sort of looks like a date string, format_translated will convert it to a Carbon instance and allow you to format it using your site's configured locale.", example = "{{ event_date | format_translated('l j F Y') }}", url = "https://statamic.dev/modifiers/format_translated"),
    StatamicDocItem(name = "full_urls", displayName = "full_urls", description = "Replaces root-relative URLs inside HTML attributes (e.g. href and src ) with absolute URLs. This is most often used in RSS feeds and other places where markup may be consumed off the domain.", example = "{{ content | full_urls }}", url = "https://statamic.dev/modifiers/full_urls"),
    StatamicDocItem(name = "get", displayName = "get", description = "Gets a value from a relationship based on its ID. This is like a nicer-to-read single tag version of the Get_Content Tag.", example = "{{ featured_post | get('title') }}", url = "https://statamic.dev/modifiers/get"),
    StatamicDocItem(name = "gravatar", displayName = "gravatar", description = "Converts an email string to a Gravatar image URL. The size can be specified by a parameter.", example = "{{ email | gravatar }}\n\n{{ email | gravatar(80) }}", url = "https://statamic.dev/modifiers/gravatar"),
    StatamicDocItem(name = "group_by", displayName = "group_by", description = "You may use this modifier to group items (a simple array, a collection of entries, etc) into groups\n\nbased on some common value.", example = "{{ sponsors | group_by('sport') }}\n\n<h1>Basketball</h2>\n\n{{ basketball }}\n\n{{ team }}\n\n{{ /basketball }}\n\n<h1>Baseball</h2>\n\n...", url = "https://statamic.dev/modifiers/group_by"),
    StatamicDocItem(name = "has_lower_case", displayName = "has_lower_case", description = "Returns true if the string contains a lowercase character, false otherwise.", example = "{{ if loud_noises | has_lower_case }}", url = "https://statamic.dev/modifiers/has_lower_case"),
    StatamicDocItem(name = "has_upper_case", displayName = "has_upper_case", description = "Returns true if the string contains an uppercase character, false otherwise.", example = "{{ if loud_noises | has_upper_case }}", url = "https://statamic.dev/modifiers/has_upper_case"),
    StatamicDocItem(name = "headline", displayName = "headline", description = "Format the given string, usually a headline or title, with either AP or MLA style.", example = "{{ title | headline('ap') }}", url = "https://statamic.dev/modifiers/headline"),
    StatamicDocItem(name = "hex_to_rgb", displayName = "hex_to_rgb", description = "Converts a color from hex to RGB, the perfect match for the color fieldtype.", example = "{{ color | hex_to_rgb }}", url = "https://statamic.dev/modifiers/hex_to_rgb"),
    StatamicDocItem(name = "hours_ago", displayName = "hours_ago", description = "Returns the number of hours since a given date variable. Statamic will attempt to parse any string as a date, but try to keep it in the least ambiguous date format possible.", example = "{{ date | hours_ago }}", url = "https://statamic.dev/modifiers/hours_ago"),
    StatamicDocItem(name = "image", displayName = "image", description = "Generate an HTML image element with the variable's value as src.", example = "{{ header_image | image }}", url = "https://statamic.dev/modifiers/image"),
    StatamicDocItem(name = "in_array", displayName = "in_array", description = "Check if an array contains a specific value. Returns true if a match is found.", example = "{{ if (shopping_list | in_array('flour')) }} GOT IT! {{ /if }}\n\n{{ if (shopping_list | in_array('want')) }} GOT EM! {{ /if }}\n\n{{ if (shopping_list | in_array('eggs', 'flour')) }} YES I DID NOT FORGET! {{ /if }}", url = "https://statamic.dev/modifiers/in_array"),
    StatamicDocItem(name = "insert", displayName = "insert", description = "Inserts a string at the position provided. The beginning of the string is position 0.", example = "{{ opinion | insert('not', 8) }}", url = "https://statamic.dev/modifiers/insert"),
    StatamicDocItem(name = "is_after", displayName = "is_after", description = "Returns true if a date variable is after another date. That second date can be the name of another variable or a literal date string.", example = "{{ if end_date | is_after(\$start_date) }}\n\n{{ if start_date | is_after(2014) }}\n\n{{ if start_date | is_after(\$end_date) }}", url = "https://statamic.dev/modifiers/is_after"),
    StatamicDocItem(name = "is_alpha", displayName = "is_alpha", description = "Returns true if string contains only alphabetic characters. Numbers, punctuation, whitespace, and another other special characters will cause a false.", example = "{{ if secret_phrase | is_alpha }}\n\n{{ if even_more_secret_phrase | is_alpha }}", url = "https://statamic.dev/modifiers/is_alpha"),
    StatamicDocItem(name = "is_alphanumeric", displayName = "is_alphanumeric", description = "Returns true if string contains only alphanumeric characters. Punctuation, whitespace, and another other special characters will cause a false.", example = "{{ if secret_phrase | is_alphanumeric }}\n\n{{ if even_more_secret_phrase | is_alphanumeric }}", url = "https://statamic.dev/modifiers/is_alphanumeric"),
    StatamicDocItem(name = "is_array", displayName = "is_array", description = "Check if a value is an array. Returns a bool.", example = null, url = "https://statamic.dev/modifiers/is_array"),
    StatamicDocItem(name = "is_before", displayName = "is_before", description = "Returns true if a date variable is before another date. That second date can be the name of another variable or a literal date string.", example = "{{ if end_date | is_before(\$start_date) }}\n\n{{ if start_date | is_before(2014) }}\n\n{{ if start_date | is_before(\$end_date) }}", url = "https://statamic.dev/modifiers/is_before"),
    StatamicDocItem(name = "is_between", displayName = "is_between", description = "Returns true if a date variable is between two other dates. Those dates can be the name of other variables or literal date strings.", example = "{{ if date | is_between(\$start_date, \$end_date) }}", url = "https://statamic.dev/modifiers/is_between"),
    StatamicDocItem(name = "is_blank", displayName = "is_blank", description = "Returns true if the string contains only whitespace chars.", example = "{{ if ghost | is_blank }}\n\n{{ if zombie | is_blank }}", url = "https://statamic.dev/modifiers/is_blank"),
    StatamicDocItem(name = "is_email", displayName = "is_email", description = "Returns true if a string is a valid email address.", example = "{{ if an_email | is_email }}\n\n{{ if not_an_email | is_email }}", url = "https://statamic.dev/modifiers/is_email"),
    StatamicDocItem(name = "is_embeddable", displayName = "is_embeddable", description = "Checks to see if a video URL is embeddable. In other words: YouTube or Vimeo URL are considered as embeddable.", example = "{{ youtube | is_embeddable }}\n\n{{ vimeo | is_embeddable }}\n\n{{ other | is_embeddable }}", url = "https://statamic.dev/modifiers/is_embeddable"),
    StatamicDocItem(name = "is_empty", displayName = "is_empty", description = "Checks to see if an array is empty without any set values. Works with numeric indexes, associative, and string keyed arrays of all depths. It's pretty smart, as these things go.", example = "{{ if some_data | is_empty }}\n\n{{ if more_data | is_empty }}", url = "https://statamic.dev/modifiers/is_empty"),
    StatamicDocItem(name = "is_external_url", displayName = "is_external_url", description = "Returns true if a string is an external URL.", example = "{{ if google_url | is_external_url }}\n\n{{ if entry_url | is_external_url }}\n\n{{ if not_a_url | is_external_url }}", url = "https://statamic.dev/modifiers/is_external_url"),
    StatamicDocItem(name = "is_future", displayName = "is_future", description = "Returns true if date is in the future.", example = "{{ if date | is_future }}\n\n{{ if another_date | is_future }}", url = "https://statamic.dev/modifiers/is_future"),
    StatamicDocItem(name = "is_json", displayName = "is_json", description = "Returns true if string is valid json", example = "{{ if data | is_json }}", url = "https://statamic.dev/modifiers/is_json"),
    StatamicDocItem(name = "is_leap_year", displayName = "is_leap_year", description = "Returns true if date is in a leap year. Try and find a regular use for this one, we dare you.", example = "{{ if date | is_leap_year }}\n\n{{ if another_date | is_leap_year }}", url = "https://statamic.dev/modifiers/is_leap_year"),
    StatamicDocItem(name = "is_lowercase", displayName = "is_lowercase", description = "Returns true if string is only lowercase characters.", example = "{{ if topic | is_lowercase }}\n\n{{ if from | is_lowercase }}", url = "https://statamic.dev/modifiers/is_lowercase"),
    StatamicDocItem(name = "is_numberwang", displayName = "is_numberwang", description = "Is it or is it not numberwang? Returns true if it is indeed numberwang.", example = "{{ if number | is_numberwang }}", url = "https://statamic.dev/modifiers/is_numberwang"),
    StatamicDocItem(name = "is_numeric", displayName = "is_numeric", description = "Returns true if variable is a number or numeric string.", example = "{{ if sequence | is_numeric }}\n\n{{ if another_sequence | is_numeric }}", url = "https://statamic.dev/modifiers/is_numeric"),
    StatamicDocItem(name = "is_past", displayName = "is_past", description = "Returns true if date is in the past.", example = "{{ if date | is_past }}\n\n{{ if another_date | is_past }}", url = "https://statamic.dev/modifiers/is_past"),
    StatamicDocItem(name = "is_today", displayName = "is_today", description = "Returns true if a given date is today, using the server's time.", example = "{{ if date | is_today }}", url = "https://statamic.dev/modifiers/is_today"),
    StatamicDocItem(name = "is_tomorrow", displayName = "is_tomorrow", description = "Returns true if a given date is tomorrow, using the server's time.", example = "{{ if date | is_tomorrow }}", url = "https://statamic.dev/modifiers/is_tomorrow"),
    StatamicDocItem(name = "is_uppercase", displayName = "is_uppercase", description = "Returns true if string is only uppercase characters.", example = "{{ if declaration | is_uppercase }}\n\n{{ if cite | is_uppercase }}", url = "https://statamic.dev/modifiers/is_uppercase"),
    StatamicDocItem(name = "is_url", displayName = "is_url", description = "Returns true if a string is a valid URL.", example = "{{ if a_url | is_url }}\n\n{{ if not_a_url | is_url }}", url = "https://statamic.dev/modifiers/is_url"),
    StatamicDocItem(name = "is_weekday", displayName = "is_weekday", description = "Returns true if date is a weekday.", example = "{{ if date | is_weekday }}", url = "https://statamic.dev/modifiers/is_weekday"),
    StatamicDocItem(name = "is_weekend", displayName = "is_weekend", description = "Returns true if date is on the weekend.", example = "{{ if date | is_weekend }}", url = "https://statamic.dev/modifiers/is_weekend"),
    StatamicDocItem(name = "is_yesterday", displayName = "is_yesterday", description = "Returns true if a given date is yesterday, using the server's time.", example = "{{ if date | is_yesterday }}", url = "https://statamic.dev/modifiers/is_yesterday"),
    StatamicDocItem(name = "iso_format", displayName = "iso_format", description = "Given a date string, or anything that even sorta kinda looks like a date string, will convert it to a Carbon instance and allow you to format it with ISO format. This allows you to use inner translations rather than language packages you need to install on every machine where you deploy your site.", example = "{{ event_date | iso_format(\"MMMM Do YYYY, h:mm:ss a\") }}", url = "https://statamic.dev/modifiers/iso_format"),
    StatamicDocItem(name = "join", displayName = "join", description = "Turn an array into a string by gluing together all the data with any specified delimiter. It uses a comma by default.", example = "{{ tasks | join }}\n\n{{ tasks | join(\" + \") }} = ready", url = "https://statamic.dev/modifiers/join"),
    StatamicDocItem(name = "kebab", displayName = "kebab", description = "Converts a string into kebab-case.", example = "{{ string | kebab }}", url = "https://statamic.dev/modifiers/kebab"),
    StatamicDocItem(name = "keys", displayName = "keys", description = "Retrieves just the keys from the given array.", example = "{{ the_team | keys }}", url = "https://statamic.dev/modifiers/keys"),
    StatamicDocItem(name = "last", displayName = "last", description = "Returns the last X characters of a string, where X is any positive integer, or the last item in an array.", example = "{{ title | last(7) }}\n\n{{ array | last }}", url = "https://statamic.dev/modifiers/last"),
    StatamicDocItem(name = "lcfirst", displayName = "lcfirst", description = "Converts the first character of the supplied string to lower case.", example = "{{ title | lcfirst }}", url = "https://statamic.dev/modifiers/lcfirst"),
    StatamicDocItem(name = "length", displayName = "length", description = "Returns the number of items in an array or characters in a string.", example = "{{ array | length }}\n\n{{ string | length }}", url = "https://statamic.dev/modifiers/length"),
    StatamicDocItem(name = "limit", displayName = "limit", description = "Limits the number of items returned in an array.", example = "{{ playlist | limit(2) | join }}", url = "https://statamic.dev/modifiers/limit"),
    StatamicDocItem(name = "link", displayName = "link", description = "Generate an HTML link element with the value as href.", example = "{{ neat_site | link }}", url = "https://statamic.dev/modifiers/link"),
    StatamicDocItem(name = "list", displayName = "list", description = "Turn a simple array into a comma delimited list with no comma after the last item.", example = "{{ things | list }}", url = "https://statamic.dev/modifiers/list"),
    StatamicDocItem(name = "lower", displayName = "lower", description = "Converts all characters in the string to lowercase.", example = "{{ yelling | lower }}", url = "https://statamic.dev/modifiers/lower"),
    StatamicDocItem(name = "macro", displayName = "macro", description = "Macro is a very special modifier. It performs no modifications of its own, but rather lets you create reusable groups of modifiers and give them a name. Those groups are each called a \"macro\" and are stored in your resources/macros.yaml file. Keep in mind that the order of modifiers within a macro matter, the same way as regular modifiers.", example = "{{ title | macro('headline') }}", url = "https://statamic.dev/modifiers/macro"),
    StatamicDocItem(name = "mailto", displayName = "mailto", description = "Generate a mailto link element with the value as the email address. If it's not an email address, it's going to be one busted link.", example = "{{ holler | mailto }}", url = "https://statamic.dev/modifiers/mailto"),
    StatamicDocItem(name = "mark", displayName = "mark", description = "Wrap any matched words in <mark> tags to highlight them on the page.", example = "{{ description | mark('cat thing') }}\n\n{{ description | mark('video', 'class:highlight') }}", url = "https://statamic.dev/modifiers/mark"),
    StatamicDocItem(name = "markdown", displayName = "markdown", description = "Transform a string with Markdown.", example = "{{ quote | markdown }}", url = "https://statamic.dev/modifiers/markdown"),
    StatamicDocItem(name = "md5", displayName = "md5", description = "Creates an md5 hash of a variable.", example = "{{ \"hello\" | md5 }}", url = "https://statamic.dev/modifiers/md5"),
    StatamicDocItem(name = "minutes_ago", displayName = "minutes_ago", description = "Returns the number of minutes since a given date variable. Statamic will attempt to parse any string as a date, but try to keep it in the least ambiguous date format possible.", example = "{{ date | minutes_ago }}", url = "https://statamic.dev/modifiers/minutes_ago"),
    StatamicDocItem(name = "mod", displayName = "mod", description = "Get the modulus value (remainder after division) of a value split by another numeric value. Pass an integer or the name of a second variable as the parameter. Also supports % as shorthand.", example = "{{ glasses | mod(14) }}\n\n{{ glasses | mod(\$bottles) }}\n\n{{ glasses | %(\$bottles) }}", url = "https://statamic.dev/modifiers/mod"),
    StatamicDocItem(name = "modify_date", displayName = "modify_date", description = "Alters a timestamp by incrementing or decrementing in a format accepted by PHP's native strtotime() method.", example = "{{ date | modify_date(\"-1 day\") }}\n\n{{ date | modify_date(\"next Sunday\") }}\n\n{{ date | modify_date(\"+3 months\") }}", url = "https://statamic.dev/modifiers/modify_date"),
    StatamicDocItem(name = "months_ago", displayName = "months_ago", description = "Returns the number of months since a given date variable. Statamic will attempt to parse any string as a date, but try to keep it in the least ambiguous date format possible.", example = "{{ date | months_ago }}", url = "https://statamic.dev/modifiers/months_ago"),
    StatamicDocItem(name = "multiply", displayName = "multiply", description = "Multiply a value or another variable to your variable. Pass an integer or the name of a second variable as the parameter. Also supports * as shorthand.", example = "{{ smiles | multiply(10) }}\n\n{{ smiles | multiply(\$winks) }}\n\n{{ smiles | *(\$winks) }}", url = "https://statamic.dev/modifiers/multiply"),
    StatamicDocItem(name = "nl2br", displayName = "nl2br", description = "Replaces line breaks with <br> tags.", example = "{{ summary | nl2br }}", url = "https://statamic.dev/modifiers/nl2br"),
    StatamicDocItem(name = "obfuscate", displayName = "obfuscate", description = "Obfuscates a string with special characters making it hard for spam bots to sniff out and scrape off your site. Still appears like the same string to the reader. This is usually used for email addresses.", example = "{{ magic_word | obfuscate }}", url = "https://statamic.dev/modifiers/obfuscate"),
    StatamicDocItem(name = "obfuscate_email", displayName = "obfuscate_email", description = "Obfuscates an email address with special characters making it hard for spam bots to sniff out and scrape off your site. Still reads like an email address as far as readers are concerned.", example = "{{ holler | obfuscate_email }}", url = "https://statamic.dev/modifiers/obfuscate_email"),
    StatamicDocItem(name = "offset", displayName = "offset", description = "Offsets the items returned in an array.", example = "{{ playlist | offset(1) | join }}", url = "https://statamic.dev/modifiers/offset"),
    StatamicDocItem(name = "ol", displayName = "ol", description = "Turn an array into an HTML ordered list element.", example = "{{ food | ol }}", url = "https://statamic.dev/modifiers/ol"),
    StatamicDocItem(name = "option_list", displayName = "option_list", description = "Turn an array into a pipe-delimited string. Useful when passing an array of things into a parameter. Generally unnecessary though as most parameters can now accept a wide range of datatypes.", example = "{{ collection from=\"{collections|option_list}\" }}", url = "https://statamic.dev/modifiers/option_list"),
    StatamicDocItem(name = "output", displayName = "output", description = "Given the URL to an Asset file, returns the string output of an Asset file's contents. This is primarily useful for rendering inline SVGs, but could also be used to display a lot of gibberish to your users if you're into that kind of thing.", example = "{{ icon | output }}", url = "https://statamic.dev/modifiers/output"),
    StatamicDocItem(name = "pad", displayName = "pad", description = "Pad an array to a given number of items with a value. By default the value is null, but you can specify it as the second parameter.", example = "{{ epic_meal_time | pad(4, \"bacon strips\") }}\n\n{{ value }}\n\n{{ /epic_meal_time }}", url = "https://statamic.dev/modifiers/pad"),
    StatamicDocItem(name = "parse_url", displayName = "parse_url", description = "Get information about a URL.", example = "{{ url | parse_url }}\n\n{{ url | parse_url('host') }}", url = "https://statamic.dev/modifiers/parse_url"),
    StatamicDocItem(name = "partial", displayName = "partial", description = "Inject a variable's data into a partial and render it without any page scopes whatsoever. This is really just syntactical sugar, but it is delicious.", example = "<!-- /site/themes/<your_theme>/partials/demo.html -->\n\n<h1>{{ title }}</h1>\n\n{{ content | markdown }}\n\n<!-- Template Markup -->\n\n{{ data | partial('demo') }}", url = "https://statamic.dev/modifiers/partial"),
    StatamicDocItem(name = "pathinfo", displayName = "pathinfo", description = "Get information about a file path.", example = "{{ path | pathinfo }}\n\n{{ path | pathinfo('extension') }}", url = "https://statamic.dev/modifiers/pathinfo"),
    StatamicDocItem(name = "piped", displayName = "piped", description = "Alias of option_list", example = null, url = "https://statamic.dev/modifiers/piped"),
    StatamicDocItem(name = "pluck", displayName = "pluck", description = "Retrieves the values of a given key from each item.", example = "{{ games | pluck('title') }}", url = "https://statamic.dev/modifiers/pluck"),
    StatamicDocItem(name = "plural", displayName = "plural", description = "Get the plural form of an English word. Accepts a numerical parameter, either as a literal value or a variable, to control plurality. It's important to note that you should use the singular form of the word to ensure the best results.", example = "Please pick up the following items:\n\n{{ shopping_list }}\n\n- {{ quantity }} {{ item | plural(\$quantity) }}.\n\n{{ /shopping_list }}", url = "https://statamic.dev/modifiers/plural"),
    StatamicDocItem(name = "random", displayName = "random", description = "Picks a single random item from an array or collection.", example = "{{ arr | random }}", url = "https://statamic.dev/modifiers/random"),
    StatamicDocItem(name = "raw", displayName = "raw", description = "Returns the unaugmented version of the variable.", example = "{{ markdown_field | raw }}", url = "https://statamic.dev/modifiers/raw"),
    StatamicDocItem(name = "rawurlencode", displayName = "rawurlencode", description = "URL-encode a variable according to RFC 3986.", example = "http://example.com/{{ example | rawurlencode }}", url = "https://statamic.dev/modifiers/rawurlencode"),
    StatamicDocItem(name = "rawurlencode_except_slashes", displayName = "rawurlencode_except_slashes", description = "URL-encode a variable according to RFC 3986. Just like rawurlencode, but doesn't encode forward slashes (/).", example = "http://example.com/{{ example | rawurlencode_except_slashes }}", url = "https://statamic.dev/modifiers/rawurlencode_except_slashes"),
    StatamicDocItem(name = "ray", displayName = "ray", description = "Send a variable to Spatie's Ray app.", example = "{{ your_field | ray }}\n\n{{ your_field | ray('red'} }", url = "https://statamic.dev/modifiers/ray"),
    StatamicDocItem(name = "read_time", displayName = "read_time", description = "Provide an estimate of the read time in minutes based on a given number of words per minute. Defaults to 200/wpm.", example = "<h1>{{ title }}</h1>\n\n<p>{{ content | read_time(180) }} min</p>", url = "https://statamic.dev/modifiers/read_time"),
    StatamicDocItem(name = "regex_mark", displayName = "regex_mark", description = "Wrap any regex matches in <mark> tags to highlight them on the page.", example = "{{ description | regex_mark('cat video|thing') }}\n\n{{ description | regex_mark('video', 'class:highlight') }}", url = "https://statamic.dev/modifiers/regex_mark"),
    StatamicDocItem(name = "regex_replace", displayName = "regex_replace", description = "Run a find and replace regex on a string of content.", example = "{{ description | regex_replace('best', 'okayest') }}", url = "https://statamic.dev/modifiers/regex_replace"),
    StatamicDocItem(name = "relative", displayName = "relative", description = "Returns a date difference in a nice, human readable, string format. This modifier will add a phrase after the difference value relative to the current date and the passed in date.", example = "{{ past_date | relative }}\n\n{{ past_date | relative(true) }}\n\n{{ future_date | relative }}\n\n{{ future_date | relative(true) }}", url = "https://statamic.dev/modifiers/relative"),
    StatamicDocItem(name = "remove_left", displayName = "remove_left", description = "Ensures that the string never begins with a specified string.", example = "<a href=\"http://twitter.com/{{ twitter | remove_left('@') }}\">Twitter</a>", url = "https://statamic.dev/modifiers/remove_left"),
    StatamicDocItem(name = "remove_right", displayName = "remove_right", description = "Ensures that the string never ends with a specified string.", example = "{{ urls }}\n\n{{ value | remove_right('/') }}\n\n{{ /urls}}", url = "https://statamic.dev/modifiers/remove_right"),
    StatamicDocItem(name = "repeat", displayName = "repeat", description = "Repeats a value any given number of times. For fun.", example = "{{ lyric | repeat(3) }}", url = "https://statamic.dev/modifiers/repeat"),
    StatamicDocItem(name = "replace", displayName = "replace", description = "Find and replace all occurrences of a string with a totally different string.", example = "{{ description | replace('cat', 'dog') }}", url = "https://statamic.dev/modifiers/replace"),
    StatamicDocItem(name = "reverse", displayName = "reverse", description = "Reverse the order of the characters in a string or the items in an array.", example = "{{ status | reverse }}\n\n{{ order_of_ceremony | reverse | list }}", url = "https://statamic.dev/modifiers/reverse"),
    StatamicDocItem(name = "round", displayName = "round", description = "Rounds a number to a specified precision (number of digits after the decimal point). Defaults to 0, or whole numbers.", example = "{{ pi | round }}\n\n{{ pi | round(2) }}", url = "https://statamic.dev/modifiers/round"),
    StatamicDocItem(name = "safe_truncate", displayName = "safe_truncate", description = "Truncates the string to a given length (parameter 1), while ensuring that\n\nit does not split words. You can append a string with parameter 2, and if truncating occurs the string is further truncated so that it may be appended without exceeding the desired length.", example = "{{ advice | safe_truncate(90, '...') }}", url = "https://statamic.dev/modifiers/safe_truncate"),
    StatamicDocItem(name = "sanitize", displayName = "sanitize", description = "Convert special characters to HTML entities with htmlspecialchars.", example = "{{ example | sanitize }}", url = "https://statamic.dev/modifiers/sanitize"),
    StatamicDocItem(name = "seconds_ago", displayName = "seconds_ago", description = "Returns the number of seconds since a given date variable. Statamic will attempt to parse any string as a date, but try to keep it in the least ambiguous date format possible.", example = "{{ date | seconds_ago }}", url = "https://statamic.dev/modifiers/seconds_ago"),
    StatamicDocItem(name = "segment", displayName = "segment", description = "Returns a segment by number from any valid URL or URI.", example = "{{ example | segment(4) }}", url = "https://statamic.dev/modifiers/segment"),
    StatamicDocItem(name = "select", displayName = "select", description = "Retrieves the selected values of a given array.", example = "{{ games | select('title', 'publisher') }}", url = "https://statamic.dev/modifiers/select"),
    StatamicDocItem(name = "sentence_list", displayName = "sentence_list", description = "Turn a simple array into a friendly comma delimited list with the word \"and\" before the last item.", example = "I like {{ things | sentence_list }}.", url = "https://statamic.dev/modifiers/sentence_list"),
    StatamicDocItem(name = "shuffle", displayName = "shuffle", description = "Shuffles a string or an array to make it all random.", example = "{{ string | shuffle }}\n\n{{ array | shuffle }}", url = "https://statamic.dev/modifiers/shuffle"),
    StatamicDocItem(name = "singular", displayName = "singular", description = "Get the singular form of an English word.", example = "{{ word | singular }}", url = "https://statamic.dev/modifiers/singular"),
    StatamicDocItem(name = "slugify", displayName = "slugify", description = "Converts the string into an URL slug. This includes replacing non-ASCII characters with their closest ASCII equivalents, removing remaining non-ASCII\n\nand non-alphanumeric characters, and replacing whitespace with dashes. And then everything is lowercased.", example = "{{ string | slugify }}", url = "https://statamic.dev/modifiers/slugify"),
    StatamicDocItem(name = "smartypants", displayName = "smartypants", description = "Translate plain ASCII punctuation characters into “smart” typographic punctuation HTML entities. It performs the following transformations:", example = "{{ conversation | smartypants }}", url = "https://statamic.dev/modifiers/smartypants"),
    StatamicDocItem(name = "snake", displayName = "snake", description = "Converts a string into snake_case.", example = "{{ string | snake }}", url = "https://statamic.dev/modifiers/snake"),
    StatamicDocItem(name = "sort", displayName = "sort", description = "Sort an array by key as parameter 1 and direction (asc/desc) as parameter 2. If sorting a primitive list no parameters are necessary.", example = "{{ primitive | sort | list }}\n\n{{ complex | sort('last_name') }}\n\nHello, {{ first_name }} {{ last_name }}\n\n{{ /complex }}\n\n{{ complex | sort('last_name', 'desc') }}\n\nHello, {{ first_name }} {{ last_name }}\n\n...", url = "https://statamic.dev/modifiers/sort"),
    StatamicDocItem(name = "spaceless", displayName = "spaceless", description = "Removes excess whitespace and line breaks from a string. A definite OCD pleaser.", example = "html: |\n\n<p>I copy & pasted\n\n<a href=\"http://goodnightchrome.show\">this link\n\n</a>   <strong>for you!</strong>    </p>", url = "https://statamic.dev/modifiers/spaceless"),
    StatamicDocItem(name = "starts_with", displayName = "starts_with", description = "Returns true if the value starts with a given string. This comparison is case-insensitive.", example = "{{ if reply | starts_with('actually') }}\n\n{{ if reply | starts_with('respectfully') }}", url = "https://statamic.dev/modifiers/starts_with"),
    StatamicDocItem(name = "str_pad_left", displayName = "str_pad_left", description = "This modifier returns the string padded on the left to the specified padding length (paramameter 1) with a character of choice (parameter 2).", example = "{{ 1 | str_pad_left(2,0) }}", url = "https://statamic.dev/modifiers/str_pad_left"),
    StatamicDocItem(name = "strip_tags", displayName = "strip_tags", description = "Strip HTML tags from a string, allowing you optionally to pass in a list of tags or a variable name containing the specific tags you want stripped.", example = "{{ html | strip_tags }}\n\n{{ html | strip_tags('p') }}\n\n{{ html | strip_tags(\$unwanted) }}", url = "https://statamic.dev/modifiers/strip_tags"),
    StatamicDocItem(name = "studly", displayName = "studly", description = "Converts a string into StudlyCase.", example = "{{ string | studly }}", url = "https://statamic.dev/modifiers/studly"),
    StatamicDocItem(name = "substr", displayName = "substr", description = "Returns the string beginning at a given position with an optional length.\n\nIf length not specific, will return the rest of the string.", example = "{{ string | substr(0, 3) }}\n\n{{ string | substr(4, 4) }}\n\n{{ string | substr(-8, 8) }}", url = "https://statamic.dev/modifiers/substr"),
    StatamicDocItem(name = "subtract", displayName = "subtract", description = "Subtract a value or another variable to your variable. Pass an integer or the name of a second variable as the parameter. Also supports - as shorthand.", example = "{{ capacity | subtract(1900) }}\n\n{{ capacity | subtract(\$reservations) }}\n\n{{ capacity | -(\$reservations) }}", url = "https://statamic.dev/modifiers/subtract"),
    StatamicDocItem(name = "sum", displayName = "sum", description = "Returns the sum of all items in an array, optionally specified by a specific key.", example = "{{ numbers | sum }}\n\n{{ stats | sum('score') }}", url = "https://statamic.dev/modifiers/sum"),
    StatamicDocItem(name = "surround", displayName = "surround", description = "Surrounds a string with another string.", example = "{{ string | surround('ʘ') }}", url = "https://statamic.dev/modifiers/surround"),
    StatamicDocItem(name = "swap_case", displayName = "swap_case", description = "Returns a case swapped version of the string.", example = "{{ string | swap_case }}", url = "https://statamic.dev/modifiers/swap_case"),
    StatamicDocItem(name = "table", displayName = "table", description = "Takes an array generated by the Table Fieldtype, and converts into a basic HTML <table>.", example = "{{ my_table | table }}", url = "https://statamic.dev/modifiers/table"),
    StatamicDocItem(name = "tidy", displayName = "tidy", description = "Returns a string with smart quotes, ellipsis characters, and dashes from Windows-1252 (commonly used in Word documents) replaced by their ASCII equivalents.", example = "{{ string | tidy }}", url = "https://statamic.dev/modifiers/tidy"),
    StatamicDocItem(name = "timezone", displayName = "timezone", description = "Applies a timezone to a date value. Aliased as tz.", example = "{{ when | format('r') }}\n\n{{ when | timezone('Australia/Sydney') | format('r') }}", url = "https://statamic.dev/modifiers/timezone"),
    StatamicDocItem(name = "title", displayName = "title", description = "Returns a trimmed string with the first letter of each word capitalized, ignoring articles, coordinating conjunctions, and short propositions: a, an, the, at, by, for, in, of, on, to, up, and, as, but, or, and nor.", example = "{{ string | title }}", url = "https://statamic.dev/modifiers/title"),
    StatamicDocItem(name = "to_json", displayName = "to_json", description = "Converts any variable into JSON.", example = "{{ stats | to_json }}", url = "https://statamic.dev/modifiers/to_json"),
    StatamicDocItem(name = "to_qs", displayName = "to_qs", description = "Converts an array or array-like value into a query string using Laravel's Arr::query() helper method.", example = "<a href=\"/search?{{ params | to_qs }}\">Search Now</a>", url = "https://statamic.dev/modifiers/to_qs"),
    StatamicDocItem(name = "to_spaces", displayName = "to_spaces", description = "Converts all tabs in a string to a given number of spaces, 4 by default. This is a boring modifier to output examples of. Here's just a few examples on how the syntax looks.", example = "{{ string | to_spaces }}\n\n{{ string | to_spaces(2) }}", url = "https://statamic.dev/modifiers/to_spaces"),
    StatamicDocItem(name = "to_tabs", displayName = "to_tabs", description = "Converts all instances of a specified number of spaces in a string to tabs. 4 by default. This is a boring modifier to output examples of. Here's just a few examples on how the syntax looks.", example = "{{ string | to_tabs }}\n\n{{ string | to_tabs(4) }}", url = "https://statamic.dev/modifiers/to_tabs"),
    StatamicDocItem(name = "trim", displayName = "trim", description = "Returns a string with whitespace removed from the start and end of the string. Supports the removal of unicode whitespace.", example = "{{ string | trim }}", url = "https://statamic.dev/modifiers/trim"),
    StatamicDocItem(name = "truncate", displayName = "truncate", description = "Truncates the string to a given length (parameter 1). You can append a string with parameter 2, and if truncating occurs the string is further truncated so that it may be appended without exceeding the desired length.", example = "{{ advice | truncate(90, '...') }}", url = "https://statamic.dev/modifiers/truncate"),
    StatamicDocItem(name = "ucfirst", displayName = "ucfirst", description = "Converts the first character of a string to upper case.", example = "{{ string | ucfirst }}", url = "https://statamic.dev/modifiers/ucfirst"),
    StatamicDocItem(name = "ul", displayName = "ul", description = "Turn an array into an HTML unordered list element.", example = "{{ food | ul }}", url = "https://statamic.dev/modifiers/ul"),
    StatamicDocItem(name = "underscored", displayName = "underscored", description = "Returns a lowercase and trimmed string separated by underscores.\n\nUnderscores are inserted before uppercase characters (with the exception\n\nof the first character of the string), and in place of spaces as well as dashes.", example = "{{ string | underscored }}", url = "https://statamic.dev/modifiers/underscored"),
    StatamicDocItem(name = "unique", displayName = "unique", description = "Returns all of the unique items in the array:", example = "{{ checklist | unique | list }}", url = "https://statamic.dev/modifiers/unique"),
    StatamicDocItem(name = "upper", displayName = "upper", description = "Transform a string into uppercase. Multi-byte friendly.", example = "{{ string | upper }}", url = "https://statamic.dev/modifiers/upper"),
    StatamicDocItem(name = "url", displayName = "url", description = "Get the URL of an Asset, Page, Entry, or Taxonomy term from an ID.", example = "{{ hero_image | url }}", url = "https://statamic.dev/modifiers/url"),
    StatamicDocItem(name = "urldecode", displayName = "urldecode", description = "URL-decodes a string. The inverse of urlencode", example = "{{ string | urldecode }}", url = "https://statamic.dev/modifiers/urldecode"),
    StatamicDocItem(name = "urlencode", displayName = "urlencode", description = "URL-encodes a string. The inverse of urldecode.", example = "{{ string | urlencode }}", url = "https://statamic.dev/modifiers/urlencode"),
    StatamicDocItem(name = "urlencode_except_slashes", displayName = "urlencode_except_slashes", description = "URL-encodes a string. Just like urlencode, but doesn't encode forward slashes (/).", example = "{{ string | urlencode_except_slashes }}", url = "https://statamic.dev/modifiers/urlencode_except_slashes"),
    StatamicDocItem(name = "values", displayName = "values", description = "Retrieves just the values from the given array.", example = "{{ the_team | values }}", url = "https://statamic.dev/modifiers/values"),
    StatamicDocItem(name = "weeks_ago", displayName = "weeks_ago", description = "Returns the number of weeks since a given date variable. Statamic will attempt to parse any string as a date, but try to keep it in the least ambiguous date format possible.", example = "{{ date | weeks_ago }}", url = "https://statamic.dev/modifiers/weeks_ago"),
    StatamicDocItem(name = "where", displayName = "where", description = "Filter an array (such as a Replicator field's data) to items where a key has a specific value.", example = "<h2>I love...</h2>\n\n{{ games | where('feeling', 'love') }}\n\n{{ title }}<br>\n\n{{ /games }}", url = "https://statamic.dev/modifiers/where"),
    StatamicDocItem(name = "where_in", displayName = "where-in", description = "Filter an array (such as a Replicator field's data) to items where a key matches specific values.", example = "<h2>I love...</h2>\n\n{{ games | where_in('feeling', ['love', 'happy']) }}\n\n{{ title }}<br>\n\n{{ /games }}", url = "https://statamic.dev/modifiers/where-in"),
    StatamicDocItem(name = "widont", displayName = "widont", description = "Attempts to prevent widows (a line with a single word) in a string by adding non-breaking spaces between the last two words of each paragraph.", example = "{{ string | widont }}\n\n{{ string | widont(4) }}", url = "https://statamic.dev/modifiers/widont"),
    StatamicDocItem(name = "word_count", displayName = "word_count", description = "Returns the number of words in a given string.", example = "{{ string | word_count }}", url = "https://statamic.dev/modifiers/word_count"),
    StatamicDocItem(name = "wrap", displayName = "wrap", description = "Wraps a string with a given HTML tag. Has the nice benefit of returning null if there is no data, eliminating the need for simple {{ if }} wrappers.", example = "{{ title | wrap('h1') }}", url = "https://statamic.dev/modifiers/wrap"),
    StatamicDocItem(name = "years_ago", displayName = "years_ago", description = "Returns the number of years since a given date variable. Statamic will attempt to parse any string as a date, but try to keep it in the least ambiguous date format possible.", example = "{{ date | years_ago }}", url = "https://statamic.dev/modifiers/years_ago")
)

